  /* The container that holds everything */
  .input-group {
    position: relative;
    margin: 20px;
    width: 300px;
    box-sizing:border-box ;
  }

  /* The actual text input */
  .input-field {
    width: 100%;
    padding: 20px 15px 10px 15px; /* Extra top padding for the label space */
    font-size: 16px;
    border: 1px solid #ccc;
    border-radius: 12px;
    outline: none;
    background-color: #f9f9f9;
    transition: border-color 0.2s;
  }

  /* Change border color on focus (the green look in your image) */
  .input-field:focus {
    border-color: #84bd00;
  }

  /* The Label positioned over the input */
  .input-label {
    position: absolute;
    left: 15px;
    top: 50%;
    transform: translateY(-50%);
    color: #999;
    pointer-events: none; /* Allows clicks to pass through to the input */
    transition: all 0.2s ease;
    text-transform: uppercase;
    font-weight: bold;
    font-size: 14px;
  }

  /* THE MAGIC PART:
     If the input is focused OR NOT showing the placeholder (meaning it has text),
     move the label up and make it smaller.
  */
  .input-field:focus + .input-label,
  .input-field:not(:placeholder-shown) + .input-label {
    top: 15px;
    font-size: 10px;
    color: #84bd00;
  }

