    <script>

        function card(){
            const category = document.getElementById('category').value;

            const cards = document.querySelectorAll('.card');

            let count_items = 0;
            const no_result = document.getElementById('no_items');
            const parent = document.getElementById('parent-content');

            cards.forEach(function(card){
                const cardCategory = card.dataset.category.trim();

                if(category === 'all' || category === cardCategory){

                    card.style.display = 'block';
                    count_items++;
                }
                
                else {

                    card.style.display = 'none';

                }


            });

                if (count_items === 0){
                    no_result.style.display = 'flex';

                }
                else {
                    no_result.style.display = 'none';
                }

        }

        function openDetail(report) {
            document.getElementById('modal-name').innerText = report.item_name;
            document.getElementById('modal-category').innerText = report.category;
            document.getElementById('modal-location').innerText = report.location_found;
            document.getElementById('modal-date').innerText = report.date_reported;
            document.getElementById('modal-description').innerText = report.description;
            
            document.getElementById('modal-status').innerText = report.status;
            document.getElementById('modal-time').innerText = report.formatted_time;

            const modalImg = document.getElementById('modal-image');
            if (report.image) {
                modalImg.src = "/storage/" + report.image;
                modalImg.style.display = "block";
            } else {
                modalImg.src = "https://tse1.mm.bing.net/th/id/OIP.T6dxufYnjnHAortYpZVq9gHaHa?pid=ImgDet&w=191&h=191&c=7&o=7&rm=3";
                // modalImg.style.display = "none";
            }

            document.querySelector('.overlay-container').style.display = 'flex';
        }

        function closeDetail() {
            document.querySelector('.overlay-container').style.display = 'none';
        }
    </script>

